mapper.select:
select u.id, u.username, u.password, u.name, u.avatar, u.manager_id as managerId, a.name as managerName, u.phone, u.email, u.create_time as createTime from user u left join admin a on u.manager_id = a.id
and u.username like concat('%', #{username}, '%')
and u.name like concat('%', #{name}, '%')
and u.manager_id = #{currentUserId}
and u.id = #{currentUserId}
order by u.id desc

mapper.update:
update user
username = #{username}, name = #{name}, avatar = #{avatar}, manager_id = #{managerId}, phone = #{phone}, email = #{email},
where id = #{id}

update user
set password = #{password}
where id = #{id}
